    public static void formattedLeague(League league) {

        Iterator<Season> itr = league.getSeasons().iterator();

        while (itr.hasNext()) {

            // Remove Seasons if the winner = null (seasons that have no data or were cancelled)
            // Iterator.remove()
            Season x = (Season) itr.next();
            if (x.getWinner() == null)
                itr.remove();
        }
    }





